def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 12) + 0.15
        elif 0.4 < ratio <= 0.7:
            acc = 0.0
            for k in range(1, 8):
                sign = -1 if k % 2 == 0 else 1
                acc += sign * (ratio ** (k + 1)) / (k * 1.2)
            score = abs(acc) + 0.08
        else:
            acc = 0.0
            for k in range(1, 10):
                sign = 1 if k % 3 == 0 else (-1 if k % 2 == 0 else 1)
                acc += sign * (ratio ** (k + 2)) / (k * 1.8)
            score = abs(acc) + 0.1
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.05
        avg_capacity = np.mean(bins[bins > 0]) if np.any(bins > 0) else 1
        density_factor = 1 / (1 + abs(capacity - avg_capacity) / avg_capacity)
        capacity_factor = np.cbrt(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + (neighbors_influence * density_factor) / capacity_factor
        if priority < 0:
            priority = 0
        if ratio < 0.1:
            priority += 0.3
        if capacity > 1 and all(capacity % d != 0 for d in range(2, int(capacity**0.5) + 1)):
            priority *= 0.95
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    min_p = np.min(priorities)
    max_p = np.max(priorities)
    if max_p - min_p > 0:
        priorities = (priorities - min_p) / (max_p - min_p) * max_finite
    return priorities
